import sqlite3
from sqlite3 import Error
import os

def create_connection():
    conn = None
    try:
        conn = sqlite3.connect('phone_directory.db')
        print("Connected to SQLite")
    except Error as e:
        print(f"Error connecting to SQLite: {e}")
    return conn

def create_table(conn):
    try:
        cur = conn.cursor()
        cur.execute("""
            CREATE TABLE IF NOT EXISTS contacts (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                phone_number TEXT NOT NULL,
                email TEXT NOT NULL
            )
        """)
        conn.commit()
        print("Table 'contacts' created successfully")
    except Error as e:
        print(f"Error creating table: {e}")

def add_contact(conn, name, phone_number, email):
    try:
        cur = conn.cursor()
        cur.execute("""
            INSERT INTO contacts (name, phone_number, email)
            VALUES (?, ?, ?)
        """, (name, phone_number, email))
        conn.commit()
        print("Contact added successfully")
    except Error as e:
        print(f"Error adding contact: {e}")

def delete_contact(conn, contact_id):
    try:
        cur = conn.cursor()
        cur.execute("""
            DELETE FROM contacts WHERE id = ?
        """, (contact_id,))
        conn.commit()
        print("Contact deleted successfully")
    except Error as e:
        print(f"Error deleting contact: {e}")

def update_contact(conn, contact_id, name, phone_number, email):
    try:
        cur = conn.cursor()
        cur.execute("""
            UPDATE contacts SET
                name = ?,
                phone_number = ?,
                email = ?
            WHERE id = ?
        """, (name, phone_number, email, contact_id))
        conn.commit()
        print("Contact updated successfully")
    except Error as e:
        print(f"Error updating contact: {e}")

def search_contacts_by_name(conn, name):
    try:
        cur = conn.cursor()
        cur.execute("""
            SELECT * FROM contacts WHERE name LIKE ?
        """, ('%' + name + '%'))
        return cur.fetchall()
    except Error as e:
        print(f"Error searching contacts: {e}")
        return []

def list_contacts_alphabetically(conn):
    try:
        cur = conn.cursor()
        cur.execute("""
            SELECT * FROM contacts ORDER BY name
        """)
        return cur.fetchall()
    except Error as e:
        print(f"Error listing contacts: {e}")
        return []

def main():
    conn = create_connection()
    if conn is not None:
        create_table(conn)
        # Example usage
        add_contact(conn, "Alice Smith", "123-456-7890", "alice@example.com")
        add_contact(conn, "Bob Johnson", "987-654-3210", "bob@example.com")
        print("Contacts:")
        for contact in list_contacts_alphabetically(conn):
            print(f"{contact[1]} - {contact[2]}")
        print("\nSearch by name:")
        results = search_contacts_by_name(conn, "Smith")
        for result in results:
            print(f"{result[1]} - {result[2]}")
        delete_contact(conn, 1)
        print("\nAfter deleting contact 1:")
        for contact in list_contacts_alphabetically(conn):
            print(f"{contact[1]} - {contact[2]}")
    else:
        print("Error connecting to database")

