import React, { useState, useEffect } from 'react';
import { useApolloClient, useQuery } from '@apollo/client';
import { FILTER_PRODUCTS_QUERY } from './queries';

const ProductFilter = () => {
  const client = useApolloClient();
  const [filters, setFilters] = useState({
    category: '',
    priceRange: [0, 100],
    rating: 4
  });
  const [products, setProducts] = useState([]);

  const { data } = useQuery(FILTER_PRODUCTS_QUERY, {
    variables: filters
  });

  useEffect(() => {
    if (data && data.products) {
      setProducts(data.products);
    }
  }, [data, filters]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFilters(prev => ({
      ...prev,
      [name]: value
    }));
  };

  return (
    <div>
      <h2>Product Filter</h2>
      <div>
        <label>
          Category:
          <select name="category" value={filters.category} onChange={handleChange}>
            <option value="">All Categories</option>
            <option value="electronics">Electronics</option>
            <option value="clothing">Clothing</option>
            <option value="books">Books</option>
          </select>
        </label>
      </div>
      <div>
        <label>
          Price Range:
          <input
            type="range"
            min="0"
            max="100"
            value={filters.priceRange[0]}
            onChange={(e) => {
              const value = parseInt(e.target.value);
              setFilters(prev => ({
                ...prev,
                priceRange: [value, filters.priceRange[1]]
              }));
            }}
          />
          <span>{filters.priceRange[0]} - {filters.priceRange[1]}</span>
        </label>
      </div>
      <div>
        <label>
          Rating:
          <select name="rating" value={filters.rating} onChange={handleChange}>
            <option value="4">4+</option>
            <option value="3">3+</option>
            <option value="2">2+</option>
            <option value="1">1+</option>
          </select>
        </label>
      </div>
      {data && data.products.length === 0 ? (
        <p>No products found.</p>
      ) : (
        <ul>
          {products.map(product => (
            <li key={product.id}>
              {product.name} - ${product.price} - {product.rating}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

export default ProductFilter;
