Session = sessionmaker(bind=engine)

# Limiter configuration
limiter = Limiter(
    app=app,
    key_func=get_remote_address,
    default_limits=["50 per minute", "500 per hour"]
)

# JWT configuration
app.config['JWT_SECRET_KEY'] = 'your-secret-key'

# Marshmallow schema
class UserSchema(Schema):
    display_name = fields.String(required=False, validate=validate.Length(3, 30))
    email = fields.String(required=False, validate=validate.Email())
    bio = fields.String(required=False, validate=validate.Length(1, 160))

    class Meta:
        strict = True

# User model
class User:
    pass

# Initialize user model
User.display_name = None
User.email = None
User.bio = None

# Initialize schema
user_schema = UserSchema()

# Route for PATCH /api/v1/users/me
@app.route('/api/v1/users/me', methods=['PATCH'])
@jwt_required()
@limiter.limit("5 per minute")
def update_user_me():
    data = request.get_json()
    user_id = get_jwt_identity()

    # Validate input
    if not data:
        abort(400, description="No JSON payload provided")

    try:
        user_schema.load(data, unknown=fields.WITHOUT_NESTING)
    except:
        abort(400, description="Invalid JSON payload")

    # Get user from database
    session = Session()
    user = session.query(User).get(user_id)

    if not user:
        abort(404, description="User not found")

    # Update fields
    for field, value in data.items():
        if field in ['display_name', 'bio']:
            if field == 'display_name':
                if not value or not validate.Length(3, 30)(value):
                    abort(400, description="Display name must be between 3 and 30 characters")
            elif field == 'bio':
                if not value or not validate.Length(1, 160)(value):
                    abort(400, description="Bio must be between 1 and 160 characters")
        elif field == 'email':
            if not value or not validate.Email(value):
                abort(400, description="Invalid email format")
            # Check if email exists in database
            email_exists = session.query(User.email).filter(User.email == value).first()
            if email_exists:
                abort(409, description="Email already exists")

    # Update user fields
    if 'display_name' in data:
        user.display_name = data['display_name']
    if 'bio' in data:
        user.bio = data['bio']
    if 'email' in data:
        user.email = data['email']

    # Save changes
    session.commit()
    session.refresh(user)

    return jsonify({
        "message": "User updated successfully"
    }), 200

if __name__ == '__main__':
    app.run(debug=True)

