class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, word):
        node = self.root
        for char in word:
            if char not in node.children:
                return False
            node = node.children[char]
        return node.is_end_of_word

    def prefix_search(self, prefix):
        node = self.root
        for char in prefix:
            if char not in node.children:
                return False
            node = node.children[char]
        return True

    def serialize(self):
        def dfs(node, path):
            if not node:
                return ""
            res = path + str(node.children)
            for child in node.children.values():
                res += dfs(child, "")
            return res

        return dfs(self.root, "")

    def deserialize(self, serialized_trie):
        self.root = TrieNode()
        def dfs(node, serialized_trie):
            if not serialized_trie:
                return
            if serialized_trie[0] == 'N':
                node = TrieNode()
                serialized_trie = serialized_trie[1:]
            else:
                node.children[serialized_trie[0]] = TrieNode()
                serialized_trie = serialized_trie[1:]
            if len(serialized_trie) > 0 and serialized_trie[0] == 'E':
                node.is_end_of_word = True
                serialized_trie = serialized_trie[1:]
            dfs(node.children[serialized_trie[0]], serialized_trie[1:])

        dfs(self.root, serialized_trie)
        return self
