@Entity
public class User {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(length = 20, unique = true)
    private String username;

    @Column(unique = true)
    private String email;

    @Column(length = 60)
    private String password;

    @Enumerated(EnumType.STRING)
    private Role role;

    @JsonInclude(JsonInclude.Include.NON_NULL)
    @JsonFormat(shape = Shape.STRING, pattern = "yyyy-MM-dd'T'HH:mm:ss.SSSZZZZZ")
    private LocalDateTime createdAt;

    // Getters and setters
}

// Role enum
public enum Role {
    ADMIN, USER
}

// User Service
@Service
public class UserService {
    @Autowired
    private UserRepository userRepository;

    public User createUser(User user) {
        if (user.getUsername().length() < 5 || user.getUsername().length() > 20) {
            throw new IllegalArgumentException("Username must be between 5 and 20 characters.");
        }

        if (!user.getEmail().matches("^\\S+@\\S+\\.[A-Za-z]+")) {
            throw new IllegalArgumentException("Invalid email format.");
        }

        if (user.getPassword().length() < 12) {
            throw new IllegalArgumentException("Password must be at least 12 characters long.");
        }

        if (!user.getPassword().matches("^(?=.*[A-Za-z])(?=.*\\d)(?=.*[!@#$%^&*()_\\-+]).{12,}$")) {
            throw new IllegalArgumentException("Password must contain at least one uppercase, one lowercase, one digit, and one special character.");
        }

        user.setCreatedAt(LocalDateTime.now());

        return userRepository.save(user);
    }
}

// User Repository
public interface UserRepository extends JpaRepository<User, Long> {
    User findByUsername(String username);
    User findByEmail(String email);
}

// User Controller
