<?php
// Plugin Module for File Upload Validation with ClamAV

// Function to check file type
function is_valid_file_type($file_type) {
    $allowed_types = ['pdf', 'doc', 'docx', 'xls', 'xlsx', 'jpg', 'jpeg', 'png'];
    return in_array($file_type, $allowed_types);
}

// Function to check file size
function is_valid_file_size($file_size) {
    $max_size = 5 * 1024 * 1024; // 5 MB
    return $file_size <= $max_size;
}

// Function to scan file with ClamAV
function scan_with_clamav($file_path) {
    $clamav = new ClamAV();
    $result = $clamav->scan($file_path);
    return $result;
}

// Plugin hook function
function validate_file_upload($file) {
    $file_type = pathinfo($file['name'], PATHINFO_EXTENSION);
    $file_size = $file['size'];
    $file_path = $file['tmp_name'];

    if (!is_valid_file_type($file_type) || !is_valid_file_size($file_size)) {
        return ['error' => 'Invalid file type or size'];
    }

    if (scan_with_clamav($file_path) === 'infected') {
        return ['error' => 'File is infected'];
    }

    return ['success' => 'File is valid'];
}
