const Koa = require('koa');
const KoaBody = require('koa-body');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');
const rateLimit = require('koa-rate-limit');

const app = new Koa();

// Rate limiting middleware
const rateLimitMiddleware = rateLimit({
  max: 100,
  window: 60 * 1000, // 1 minute
  message: 'Too many requests. Please try again later.'
});

// Secret key for HMAC validation
const SECRET_KEY = 'your-secret-key-here';

// Middleware for parsing request body
app.use(KoaBody());

// Middleware for rate limiting
app.use(rateLimitMiddleware);

// Middleware for HMAC validation
app.use(async (ctx, next) => {
  const { method, url, headers } = ctx;

  // Check if request is POST
  if (method !== 'POST') {
    ctx.status = 405;
    ctx.body = 'Method not allowed';
    return;
  }

  // Extract HMAC signature from headers
  const hmacSignature = headers['x-hmac-signature'];

  // Extract request body
  const body = await ctx.request.body;

  // Validate HMAC signature
  const signature = crypto.createHmac('sha256', SECRET_KEY)
    .update(JSON.stringify(body))
    .digest('base64');

  if (hmacSignature !== signature) {
    ctx.status = 401;
    ctx.body = 'Invalid HMAC signature';
    return;
  }

  // Proceed to handle the request
  await next();
});

// Middleware for logging
app.use(async (ctx, next) => {
  const startTime = Date.now();
  await next();
  const endTime = Date.now();
  const duration = endTime - startTime;

  // Log request details
  ctx.logger.info(`Request ${ctx.method} to ${ctx.path} - Duration: ${duration}ms`);
});

// Routes
app.use(async (ctx) => {
  const { method, path } = ctx;

  if (method === 'GET') {
    // Handle GET requests (e.g., list webhooks)
    if (path === '/webhooks') {
      ctx.body = JSON.stringify(ctx.state.webhooks);
    } else {
      ctx.status = 404;
      ctx.body = 'Not found';
    }
  } else if (method === 'POST') {
    // Handle POST requests (e.g., create webhook)
    if (path === '/webhooks') {
      const body = await ctx.request.body;
      const { name, url, events, secretKey } = body;

      // Validate required fields
      if (!name || !url || !events || !secretKey) {
        ctx.status = 400;
        ctx.body = 'Missing required fields';
        return;
      }

      // Store webhook in state
      ctx.state.webhooks.push({ name, url, events, secretKey });

      ctx.status = 201;
      ctx.body = 'Webhook created successfully';
    } else {
      ctx.status = 404;
      ctx.body = 'Not found';
    }
  } else {
    ctx.status = 405;
    ctx.body = 'Method not allowed';
  }
});

