        data = request.data
        try:
            # Check if patient_id is already exists
            if Patient.objects.filter(patient_id=data['patient_id']).exists():
                raise ValidationError("Patient ID already exists.")
            # Create the patient
            patient = Patient.objects.create(
                patient_id=data['patient_id'],
                name=data['name'],
                dob=data['dob'],
                gender=data['gender'],
                address=data.get('address', '')
            )
            return Response({
                'status': 'success',
                'data': PatientSerializer(patient, many=False).data
            }, status=status.HTTP_201_CREATED)
        except ValidationError as e:
            return Response({
                'status': 'error',
                'message': str(e)
            }, status=status.HTTP_400_BAD_REQUEST)

