// payment.service.js
import { Injectable } from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model } from 'mongoose';
import { Payment } from './payment.model';
import { StripeService } from './stripe.service';
import { validate } from 'class-validator';

@Injectable()
export class PaymentService {
  constructor(
    @InjectModel(Payment.name)
    private readonly paymentModel: Model<Payment>,
    private readonly stripeService: StripeService
  ) {}

  async createPayment(payload) {
    // Validate input
    const validationErrors = await validate(payload);
    if (validationErrors.length > 0) {
      throw new Error(JSON.stringify(validationErrors));
    }

    // Start transaction
    try {
      const transaction = await this.paymentModel.startSession();
      transaction.startWriteConcern({ timeout: 30000 });

      // Persist payment in MongoDB
      const payment = new this.paymentModel(payload);
      const result = await payment.save({ session: transaction });

      // Call Stripe API
      const stripeResult = await this.stripeService.createPaymentIntent(
        payload.amount,
        payload.currency,
        payload.customerId
      );

      if (stripeResult.success) {
        // Update payment with Stripe ID
        await transaction.updateOne(
          { _id: payment._id },
          { $set: { stripePaymentIntentId: stripeResult.id } }
        );

        return {
          paymentId: payment._id,
          clientSecret: stripeResult.clientSecret
        };
      } else {
        // Rollback transaction and log error
        await transaction.abort();
        throw new Error(stripeResult.error);
      }
    } catch (error) {
      // Rollback transaction and log error
      await this.paymentModel.endSession();
      console.error('Error in payment service:', error);
      throw new Error(JSON.stringify(error));
    }
  }
}
