valid_conditions = ['hypertension', 'diabetes', 'asthma', 'hypothyroidism', 'obesity']

@app.route('/patient/<patient_id>', methods=['PUT'])
def update_patient(patient_id):
    # Validate incoming data
    data = request.get_json()
    if not data:
        return jsonify({"error": "No JSON provided"}), 400

    name = data.get('name')
    age = data.get('age')
    conditions = data.get('conditions')

    if not all([name, age, conditions]):
        return jsonify({"error": "All fields are required"}), 400

    if not isinstance(age, int) or age < 0:
        return jsonify({"error": "Age must be a non-negative integer"}), 400

    if not all(isinstance(condition, str) for condition in conditions):
        return jsonify({"error": "All conditions must be strings"}), 400

    if not set(conditions).issubset(valid_conditions):
        return jsonify({"error": "Invalid condition"}), 400

    # Update the patient in MongoDB
    update_result = patients_collection.update_one(
        {"_id": patient_id},
        {"$set": {
            "name": name,
            "age": age,
            "conditions": conditions
        }}
    )

    if update_result.modified_count == 0:
        return jsonify({"error": "Patient not found"}), 400

    # Return success response
    return jsonify({
        "status": "success",
        "message": "Patient record updated successfully",
        "patient": {
            "_id": patient_id,
            "name": name,
            "age": age,
            "conditions": conditions
        }
