from flask import Flask, request, jsonify
from flask_pymongo import PyMongo
from datetime import datetime
import re

app = Flask(__name__)
app.config['MONGO_URI'] = 'mongodb://localhost:27017/educational_system'
mongo = PyMongo(app)

def validate_class_data(data):
    required_fields = ['title', 'start_time', 'duration_minutes']
    optional_fields = ['description']

    for field in required_fields:
        if field not in data or data[field] is None:
            return False, f"Missing required field: {field}"

    if not re.match(r'^[0-9]{2}:[0-5][0-9}$', data['start_time']):
        return False, "Invalid start time format (HH:MM)"

    if data['duration_minutes'] <= 0:
        return False, "Duration must be a positive integer"

    for field in optional_fields:
        if field not in data or data[field] is None:
            continue
        if field == 'description':
            if not isinstance(data[field], str) or len(data[field]) < 1:
                return False, "Description must be a non-empty string"

    return True, None

@app.route('/schedule_class', methods=['POST'])
def schedule_class():
    data = request.get_json()
    validation_result, error = validate_class_data(data)
    if not validation_result:
        return jsonify({"error": error}), 400

    class_id = mongo.db.classes.insert_one(data).insert_id
    return jsonify({"class_id": class_id, "message": "Class scheduled successfully"}), 201

@app.errorhandler(400)
def handle_400(error):
    return jsonify({"error": str(error)}), 400

@app.errorhandler(404)
def handle_404(error):
    return jsonify({"error": str(error)}), 404

if __name__ == '__main__':
    app.run(debug=True)
