        "description": "You are in a kitchen. There is a table with a knife and a plate.",
        "items": ["knife", "plate"],
        "actions": ["go back", "take knife", "take plate"]
    },
    "library": {
        "description": "You are in a library. There are books on the shelves.",
        "items": ["book1", "book2"],
        "actions": ["go back", "take book1", "take book2"]
    }
}

# Initialize player state
player_state = {
    "location": "hallway",
    "inventory": [],
    "saved_game": None
}

# Save game to JSON
def save_game():
    with open("saved_game.json", "w") as file:
        json.dump(player_state, file)

# Load game from JSON
def load_game():
    if os.path.exists("saved_game.json"):
        with open("saved_game.json", "r") as file:
            player_state = json.load(file)
    return player_state

# Display room description
def display_room(room):
    print(f"\n{room['description']}")
    print("Items in room:", ", ".join(room["items"]))
    print("Available actions: " + ", ".join(room["actions"]))

# Handle player input
def get_player_input():
    action = input("Enter your action (go [direction], take [item], quit): ").lower()
    return action

# Main game loop
def play_game():
    player_state = load_game()
    print("Welcome to the Castle Adventure!")
    while True:
        display_room(player_state["location"])
        action = get_player_input()

        if action == "quit":
            print("Game saved. Goodbye!")
            save_game()
            break
        elif action.startswith("go"):
            direction = action[3:]
            if direction in ROOMS[player_state["location"]]["actions"]:
                player_state["location"] = direction
            else:
                print("Invalid direction.")
        elif action.startswith("take"):
            item = action[4:]
            if item in ROOMS[player_state["location"]]["items"]:
                player_state["inventory"].append(item)
                print(f"You take the {item}.")
            else:
                print("You cannot take that item.")
        else:
            print("Invalid action.")

# Run the game
if __name__ == "__main__":
    play_game()
