using Polly;
using Swashbuckle.AspNetCore.Annotations;
using Xunit;
using Moq;
using System.Reflection;

// Define the model for the response
public class CurrencyConversionResponse
{
    public string FromCurrency { get; set; }
    public string ToCurrency { get; set; }
    public decimal ExchangeRate { get; set; }
    public decimal OriginalAmount { get; set; }
    public decimal ConvertedAmount { get; set; }
    public DateTime Timestamp { get; set; }
}

// Define the model for the error response
public class ErrorDetails
{
    public string Error { get; set; }
    public string Details { get; set; }
}

// Define the model for the API response
[SwaggerResponse(200, Type = typeof(CurrencyConversionResponse), Description = "Currency conversion successful")]
[SwaggerResponse(400, Type = typeof(ErrorDetails), Description = "Invalid input")]
[SwaggerResponse(401, Type = typeof(ErrorDetails), Description = "Missing or invalid API key")]
[SwaggerResponse(503, Type = typeof(ErrorDetails), Description = "Rate service unavailable")]
[SwaggerResponse(500, Type = typeof(ErrorDetails), Description = "Internal server error")]
public class CurrencyConversionController : ControllerBase
{
    private readonly IMemoryCache _cache;
    private readonly IHttpClientFactory _httpClientFactory;
    private readonly IOptions<RateServiceOptions> _rateServiceOptions;
    private readonly ILogger<CurrencyConversionController> _logger;
    private readonly ICacheManager _cacheManager;
    private readonly IRateService _rateService;

    public CurrencyConversionController(
        IMemoryCache cache,
        IHttpClientFactory httpClientFactory,
        IOptions<RateServiceOptions> rateServiceOptions,
        ILogger<CurrencyConversionController> logger,
        ICacheManager cacheManager,
        IRateService rateService)
    {
        _cache = cache;
        _httpClientFactory = httpClientFactory;
        _rateServiceOptions = rateServiceOptions;
        _logger = logger;
        _cacheManager = cacheManager;
        _rateService = rateService;
    }

    [HttpGet("convert")]
    [SwaggerResponse(200, Type = typeof(CurrencyConversionResponse), Description = "Currency conversion successful")]
    [SwaggerResponse(400, Type = typeof(ErrorDetails), Description = "Invalid input")]
    [SwaggerResponse(401, Type = typeof(ErrorDetails), Description = "Missing or invalid API key")]
    [SwaggerResponse(503, Type = typeof(ErrorDetails), Description = "Rate service unavailable")]
    [SwaggerResponse(500, Type = typeof(ErrorDetails), Description = "Internal server error")]
    public async Task<IActionResult> Convert([FromQuery] string fromCurrency, [FromQuery] string toCurrency, [FromQuery] decimal amount)
    {
        if (string.IsNullOrEmpty(fromCurrency) || string.IsNullOrEmpty(toCurrency) || amount <= 0)
        {
            return BadRequest(new ErrorDetails
            {
                Error = "Invalid input",
                Details = "fromCurrency, toCurrency, and amount must be provided and amount must be greater than 0."
            });
        }

        if (!CurrencyUtils.IsValidCurrency(fromCurrency) || !CurrencyUtils.IsValidCurrency(toCurrency))
        {
            return BadRequest(new ErrorDetails
            {
                Error = "Invalid currency",
                Details = "fromCurrency and toCurrency must be valid ISO 4217 currency codes."
            });
        }

        var cacheKey = $"{fromCurrency}_{toCurrency}";
        var cachedRate = _cache.Get<decimal>(cacheKey);

        if (cachedRate != null)
        {
            return Ok(new CurrencyConversionResponse
            {
                FromCurrency = fromCurrency,
                ToCurrency = toCurrency,
                ExchangeRate = cachedRate,
                OriginalAmount = amount,
                ConvertedAmount = amount * cachedRate,
                Timestamp = DateTime.UtcNow
            });
        }

        var httpClient = _httpClientFactory.CreateClient("RateService");
        var policy = Policy
            .Handle<Exception>()
            .Retry(3)
            .WaitAndRetry(
                retryCount: 3,
                onRetry: (exception, timesAttempted) =>
                {
                    _logger.LogWarning("Retry attempt {Attempt} for rate service failure: {Exception}", timesAttempted, exception.Message);
                    return Task.CompletedTask;
                },
                sleepDuration: retryDuration => 
                {
                    // Exponential backoff
                    return TimeSpan.FromSeconds(Math.Pow(2, timesAttempted));
                });

        var response = await policy.ExecuteAsync(async () =>
        {
            var result = await httpClient.GetFromJsonAsync<RateResponse>($"https://exchangeratesapi.io/v2/latest?base={fromCurrency}");
            if (result == null)
            {
                throw new Exception("Failed to fetch exchange rates from external API.");
            }

            if (!result.Success)
            {
                throw new Exception($"Exchange rates API returned error: {result.Message}");
            }

            var exchangeRate = result.Rates[toCurrency];
            _cache.Set(cacheKey, exchangeRate, TimeSpan.FromMinutes(5));

            return new RateResponse
            {
                Success = true,
                Message = "Exchange rates retrieved successfully.",
                Rates = result.Rates
            };
        });

        if (response.Success)
        {
            return Ok(new CurrencyConversionResponse
            {
                FromCurrency = fromCurrency,
                ToCurrency = toCurrency,
                ExchangeRate = response.Rates[toCurrency],
                OriginalAmount = amount,
                ConvertedAmount = amount * response.Rates[toCurrency],
                Timestamp = DateTime.UtcNow
            });
        }
        else
        {
            return StatusCode(503, new ErrorDetails
            {
                Error = "Rate service unavailable",
                Details = "Failed to retrieve exchange rates from the external service."
            });
        }
    }

    private static TimeSpan retryDuration(int attempt)
    {
        return TimeSpan.FromSeconds(Math.Pow(2, attempt));
    }
}

// Mock for RateService
public class RateServiceMock : IRateService
{
    public async Task<RateResponse> GetRatesAsync(string baseCurrency)
    {
        // Simulate a successful response
        return new RateResponse
        {
            Success = true,
            Message = "Exchange rates retrieved successfully.",
            Rates = new Dictionary<string, decimal>
            {
                { "USD", 1.0m },
                { "EUR", 0.85m }
            }
        };
    }
}

// RateResponse model
public class RateResponse
{
    public bool Success { get; set; }
    public string Message { get; set; }
    public Dictionary<string, decimal> Rates { get; set; }
}

// CurrencyUtils class
public static class CurrencyUtils
{
    public static bool IsValidCurrency(string currencyCode)
    {
        return currencyCode != null && currencyCode.Length <= 3 && 
               new string(currencyCode.Where(c => char.IsLetter(c)).ToArray()).Length == 3;
    }
}

// CacheManager class
public class CacheManager
{
    private readonly IMemoryCache _cache;
    public CacheManager(IMemoryCache cache)
    {
        _cache = cache;
    }

    public void Set(string key, object value, int expiration)
    {
        _cache.Set(key, value, TimeSpan.FromMinutes(expiration));
    }

    public object Get(string key)
    {
        return _cache.Get(key);
    }
}

// RateServiceOptions
public class RateServiceOptions
{
    public string BaseCurrency { get; set; }
}
