from .models import Subscription

class SubscriptionForm(forms.ModelForm):
    class Meta:
        model = Subscription
        fields = ['user_id', 'subscription_status']

class SubscriptionView:
    def get(self, request):
        form = SubscriptionForm()
        return render(request, 'subscription_form.html', {'form': form})

    def post(self, request):
        form = SubscriptionForm(request.POST)
        if form.is_valid():
            try:
                with transaction.atomic():
                    user_id = form.cleaned_data['user_id']
                    subscription_status = form.cleaned_data['subscription_status']
                    # Update subscription status
                    Subscription.objects.filter(user_id=user_id).update(subscription_status=subscription_status, update_timestamp=timezone.now())
                    return HttpResponseRedirect(reverse('subscription_success'))
            except Exception as e:
                # Handle errors
                return render(request, 'subscription_form.html', {'form': form, 'error': str(e)})
        return render(request, 'subscription_form.html', {'form': form})

