import csv
from collections import namedtuple

Task = namedtuple('Task', ['name', 'priority', 'duration'])

def read_tasks_from_csv(file_path):
    tasks = []
    with open(file_path, 'r') as file:
        csv_reader = csv.DictReader(file)
        for row in csv_reader:
            tasks.append(Task(row['name'], int(row['priority']), int(row['duration'])))
    return tasks

def sort_tasks(tasks):
    return sorted(tasks, key=lambda task: (task.priority, task.duration))

def print_schedule(tasks):
    for task in tasks:
        print(f"Task: {task.name}, Priority: {task.priority}, Duration: {task.duration}")

# Example usage
if __name__ == "__main__":
    file_path = 'tasks.csv'
    tasks = read_tasks_from_csv(file_path)
    sorted_tasks = sort_tasks(tasks)
    print_schedule(sorted_tasks)
